#!/usr/bin/env python3
"""Markov-chain style usage fuzzer. Samples probes across discovered modes."""

import os, random, shutil, subprocess, sys, string

REF = "/workspace/executable"
SUT = "/work/work/executable"
random.seed(20260527)

failures = []
passes = 0


def run(binary, args, stdin=b''):
    p = subprocess.run([binary] + args, input=stdin, capture_output=True, timeout=30)
    return p.returncode, p.stdout, p.stderr


def diff(name, args, stdin=b''):
    global passes
    rc_r, so_r, se_r = run(REF, args, stdin=stdin)
    rc_s, so_s, se_s = run(SUT, args, stdin=stdin)
    if (rc_r, so_r, se_r) != (rc_s, so_s, se_s):
        failures.append((name, args, stdin, (rc_r, so_r, se_r), (rc_s, so_s, se_s)))
    else:
        passes += 1


def random_args():
    """Sample a random argv list using a usage Markov chain over flags+positions."""
    args = []
    # Decide mode
    mode = random.choice(['default', 'default', 'default', 'check', 'tag', 'keyed', 'derive-key', 'raw'])
    if mode == 'check':
        args.append('--check')
        if random.random() < 0.3:
            args.append('--quiet')
        if random.random() < 0.3:
            args.append('--seek'); args.append(str(random.randint(0, 100)))
    elif mode == 'tag':
        args.append('--tag')
        if random.random() < 0.3:
            args.append('--length'); args.append(str(random.randint(0, 200)))
    elif mode == 'keyed':
        args.append('--keyed')
        if random.random() < 0.3:
            args.append('--length'); args.append(str(random.randint(1, 100)))
        if random.random() < 0.2:
            args.append('--raw')
    elif mode == 'derive-key':
        args.append('--derive-key')
        # Random context
        L = random.randint(0, 30)
        chars = string.ascii_letters + string.digits + ' '
        args.append(''.join(random.choice(chars) for _ in range(L)))
        if random.random() < 0.3:
            args.append('--length'); args.append(str(random.randint(0, 100)))
    elif mode == 'raw':
        args.append('--raw')
        if random.random() < 0.3:
            args.append('--length'); args.append(str(random.randint(0, 100)))
    else:  # default
        if random.random() < 0.3:
            args.append('--length'); args.append(str(random.randint(0, 200)))
        if random.random() < 0.3:
            args.append('--seek'); args.append(str(random.randint(0, 100)))
        if random.random() < 0.2:
            args.append('--no-names')
        if random.random() < 0.2:
            args.append('--tag')

    # File args
    n_files = random.choice([0, 1, 1, 1, 2, 3])
    files = []
    for _ in range(n_files):
        f = random.choice(['a.txt', 'empty.txt', 'big.bin', '-', 'nonexistent.txt', 'space file.txt'])
        files.append(f)
    args.extend(files)
    return args, mode


def fuzz_iteration(iter_n):
    args, mode = random_args()
    if mode == 'keyed':
        stdin = bytes(random.getrandbits(8) for _ in range(32))
    elif mode == 'derive-key':
        stdin = bytes(random.getrandbits(8) for _ in range(random.randint(0, 100)))
    elif mode == 'check':
        # Build a check file content
        lines = []
        for _ in range(random.randint(0, 5)):
            kind = random.choice(['ok', 'bad', 'invalid'])
            if kind == 'ok':
                lines.append(b"6437b3ac38465133ffb63b75273a8db548c558465d79db03fd359c6cd5bd9d85  a.txt")
            elif kind == 'bad':
                lines.append(b"0" * 64 + b"  a.txt")
            else:
                lines.append(b"not valid line")
        stdin = b"\n".join(lines) + (b"\n" if lines else b"")
    else:
        L = random.choice([0, 1, 10, 100, 1000, 65536])
        stdin = bytes(random.getrandbits(8) for _ in range(L))

    diff(f"fuzz_{iter_n}_{mode}", args, stdin=stdin)


def main():
    tmp = "/tmp/b3test_fuzz"
    if os.path.exists(tmp):
        shutil.rmtree(tmp)
    os.makedirs(tmp)
    os.chdir(tmp)

    with open("a.txt", "wb") as f:
        f.write(b"abc")
    with open("empty.txt", "wb") as f:
        f.write(b"")
    with open("big.bin", "wb") as f:
        f.write(bytes(range(256)) * 256)  # 64 KB
    with open("space file.txt", "wb") as f:
        f.write(b"test")

    N = int(sys.argv[1]) if len(sys.argv) > 1 else 30
    for i in range(N):
        try:
            fuzz_iteration(i)
        except subprocess.TimeoutExpired:
            print(f"Iteration {i} timed out, skipping")

    print(f"{passes} passed, {len(failures)} failed")
    for name, args, stdin, ref, sut in failures[:10]:
        print(f"\n--- FAIL: {name} args={args!r} stdin_len={len(stdin)}")
        print(f"REF rc={ref[0]} stdout={ref[1][:200]!r} stderr={ref[2][:200]!r}")
        print(f"SUT rc={sut[0]} stdout={sut[1][:200]!r} stderr={sut[2][:200]!r}")
    return len(failures)


if __name__ == "__main__":
    sys.exit(1 if main() > 0 else 0)

